import { Component, computed, inject, OnInit, signal } from '@angular/core';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { QuizService } from '../../../core/services/quiz.service';
import { AuthService } from '../../../core/services/auth.service';
import { ToastService } from '../../../core/services/toast.service';
import { ConfirmService } from '../../../core/services/confirm.service';
import { QuizSummaryDto } from '../../../core/models/quiz.models';
import { CourseNavComponent } from '../../../shared/course-nav/course-nav';

/**
 * Course quizzes index — /courses/:courseId/quizzes
 * Canvas-style routed list with the shared course sidebar.
 */
@Component({
  selector: 'app-course-quizzes',
  standalone: true,
  imports: [RouterLink, CourseNavComponent],
  template: `
    <div class="course-layout">
      <app-course-nav [courseId]="courseId()" active="quizzes" />

      <main class="course-main">
        <div class="cq-head">
          <a [routerLink]="['/courses', courseId()]" class="back-link">
            <span class="material-icons">arrow_back</span> Back to course
          </a>
          <div class="cq-title-row">
            <h1>Quizzes</h1>
            @if (isAdmin()) {
              <a class="btn btn-primary btn-sm" [routerLink]="['/courses', courseId(), 'quizzes', 'new']">
                <span class="material-icons" style="font-size:16px;">add</span> New Quiz
              </a>
            }
          </div>
        </div>

        @if (loading()) {
          <div class="loading-spinner"><div class="spinner"></div></div>
        } @else {
          <div class="card">
            <div class="pages-list">
              @for (q of quizzes(); track q.id) {
                <div class="page-row" (click)="open(q)">
                  <span class="material-icons quiz-icon">quiz</span>
                  <div class="page-main">
                    <strong>{{ q.title }}</strong>
                    <span class="page-meta">
                      {{ q.maxAttempts }} attempt(s) · {{ q.passingScorePercent }}% to pass
                      @if (q.timeLimitMinutes) { · {{ q.timeLimitMinutes }} min }
                    </span>
                  </div>
                  @if (isAdmin()) {
                    <div class="page-actions" (click)="$event.stopPropagation()">
                      <a class="icon-btn" [routerLink]="['/quiz', q.id, 'edit']" title="Edit questions & settings">
                        <span class="material-icons">edit</span>
                      </a>
                      <button class="icon-btn icon-btn-danger" (click)="remove(q)" title="Delete quiz">
                        <span class="material-icons">delete</span>
                      </button>
                    </div>
                  }
                </div>
              } @empty {
                <div class="empty-state"><span class="material-icons">quiz</span>
                  @if (isAdmin()) {
                    <p>No quizzes yet. Create one and reference it from any module.</p>
                  } @else {
                    <p>No quizzes available yet.</p>
                  }
                </div>
              }
            </div>
          </div>
        }
      </main>
    </div>
  `,
  styleUrl: './course-quizzes.scss',
})
export class CourseQuizzesComponent implements OnInit {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private qSvc = inject(QuizService);
  private auth = inject(AuthService);
  private toast = inject(ToastService);
  private confirm = inject(ConfirmService);

  readonly courseId = signal(0);
  readonly quizzes = signal<QuizSummaryDto[]>([]);
  readonly loading = signal(true);
  readonly isAdmin = computed(() => this.auth.hasRole('PlatformAdmin', 'Instructor'));

  ngOnInit(): void {
    this.courseId.set(Number(this.route.snapshot.paramMap.get('courseId')));
    this.load();
  }

  private load(): void {
    this.loading.set(true);
    this.qSvc.getByCourse(this.courseId()).subscribe({
      next: list => { this.quizzes.set(list); this.loading.set(false); },
      error: (e: Error) => { this.loading.set(false); this.toast.error(`Failed to load quizzes: ${e.message}`); },
    });
  }

  open(q: QuizSummaryDto): void {
    this.router.navigate(['/courses', this.courseId(), 'quizzes', q.id]);
  }

  async remove(q: QuizSummaryDto): Promise<void> {
    const ok = await this.confirm.ask({
      title: 'Delete quiz',
      message: `Delete "${q.title}" and all its questions? Existing attempts will be preserved.`,
      confirmLabel: 'Delete',
      danger: true,
    });
    if (!ok) return;
    this.qSvc.delete(q.id).subscribe({
      next: () => { this.toast.success('Quiz deleted.'); this.load(); },
      error: (e: Error) => this.toast.error(`Failed to delete quiz: ${e.message}`),
    });
  }
}
